     1→/* Hey Chill — Service Worker */
     2→'use strict';
     3→
     4→const CACHE_NAME = 'hey-chill-v5';
     5→
     6→// App shell assets to cache on install
     7→const APP_SHELL = [
     8→  '/',
     9→  '/index.html',
    10→  '/app.js',
    11→  '/style.css',
    12→  '/manifest.json',
    13→  '/icons/icon-192.svg',
    14→  '/icons/icon-512.svg',
    15→];
    16→
    17→/* ===== Install: pre-cache app shell ===== */
    18→self.addEventListener('install', (event) => {
    19→  event.waitUntil(
    20→    caches.open(CACHE_NAME).then((cache) => cache.addAll(APP_SHELL))
    21→  );
    22→  // Activate immediately without waiting for tabs to close
    23→  self.skipWaiting();
    24→});
    25→
    26→/* ===== Activate: clean up old caches ===== */
    27→self.addEventListener('activate', (event) => {
    28→  event.waitUntil(
    29→    caches.keys().then((keys) =>
    30→      Promise.all(
    31→        keys
    32→          .filter((k) => k !== CACHE_NAME)
    33→          .map((k) => caches.delete(k))
    34→      )
    35→    )
    36→  );
    37→  // Take control of all clients immediately
    38→  self.clients.claim();
    39→});
    40→
    41→/* ===== Fetch: cache-first for shell, network-first for API ===== */
    42→self.addEventListener('fetch', (event) => {
    43→  const { request } = event;
    44→  const url = new URL(request.url);
    45→
    46→  // Only handle same-origin GET requests (don't intercept webhook POSTs)
    47→  if (request.method !== 'GET' || url.origin !== self.location.origin) {
    48→    return;
    49→  }
    50→
    51→  event.respondWith(
    52→    caches.match(request).then((cached) => {
    53→      if (cached) return cached;
    54→
    55→      return fetch(request).then((response) => {
    56→        // Cache successful responses for app shell resources
    57→        if (response.ok) {
    58→          const clone = response.clone();
    59→          caches.open(CACHE_NAME).then((cache) => cache.put(request, clone));
    60→        }
    61→        return response;
    62→      }).catch(() => {
    63→        // Offline fallback — return index.html for navigation requests
    64→        if (request.destination === 'document') {
    65→          return caches.match('/index.html');
    66→        }
    67→      });
    68→    })
    69→  );
    70→});
    71→

