### Transcript Cleaning Function (lines 43-66)
```javascript
function cleanTranscript(raw) {
  // Strip filler sounds: um, uh, er, hmm, mhm
  let text = raw.replace(/\b(um+|uh+|er+|hmm+|mhm)\b\s*/gi, ' ');

  // Collapse whitespace
  text = text.replace(/\s+/g, ' ').trim();

  // Capitalize first letter
  if (text) text = text.charAt(0).toUpperCase() + text.slice(1);

  // Capitalize after sentence punctuation
  text = text.replace(/([.!?])\s+([a-z])/g, (_, p, l) => `${p} ${l.toUpperCase()}`);

  // Add terminal period if absent
  if (text && !/[.!?…]$/.test(text)) text += '.';

  return text;
}
```

